from openai import OpenAI
import json

client_oai = OpenAI()

WEB_SEARCH_TOOL = {
    "type": "function",
    "function": {
        "name": "web_search",
        "description": (
            "Search the web for current information. Use when the user asks about "
            "recent events, news, live data, or anything that may have changed "
            "since your training cutoff. Returns a list of relevant web snippets."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "The search query. Be specific and concise.",
                },
                "max_results": {
                    "type": "integer",
                    "description": "Number of results to return (1-10).",
                    "default": 5,
                    "minimum": 1,
                    "maximum": 10,
                },
            },
            "required": ["query"],
            "additionalProperties": False,
        },
    },
}

def format_search_results(results: list[dict]) -> str:
    """Format results into a readable string for the LLM."""
    lines = []
    for i, r in enumerate(results, 1):
        lines.append(f"[{i}] {r['title']}\nURL: {r['url']}\n{r['content']}\n")
    return "\n".join(lines)

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = client_oai.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=[WEB_SEARCH_TOOL],
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)
        if choice.finish_reason == "stop":
            return choice.message.content
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            results = web_search(**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": format_search_results(results),
            })

answer = run_agent("What are the main features in the latest Python 3.13 release?")
print(answer)

def format_web_results(results: list[dict], max_chars_per_result: int = 500) -> str:
    """Format web search results for the LLM context window."""
    lines = ["Search results:\n"]
    for i, r in enumerate(results, 1):
        snippet = r["content"][:max_chars_per_result]
        if len(r["content"]) > max_chars_per_result:
            snippet += "..."
        lines.append(
            f"[{i}] {r['title']}\n"
            f"Source: {r['url']}\n"
            f"{snippet}\n"
        )
    return "\n".join(lines)

def format_doc_results(docs: list, max_chars: int = 600) -> str:
    """Format vector search results for the LLM context window."""
    parts = []
    for doc in docs:
        source = doc.metadata.get("source", "internal")
        page = doc.metadata.get("page", "")
        header = f"[{source}" + (f", p.{page}" if page else "") + "]"
        content = doc.page_content[:max_chars]
        parts.append(f"{header}\n{content}")
    return "\n\n".join(parts)
